graphql.query:
query($zip: String!) {
  tax_assessor(where: { situs_zip_code: { _eq: $zip } }, limit: 25) {
    tax_assessor_id
    assessed_value_total
    market_value_total
    year_built
  }
}

query {
  recorder(where: { fips_code: { _eq: "06037" } }, order_by: { document_recorded_date: desc }, limit: 50) {
    recorder_id
    document_type
    document_recorded_date
    document_amount
    grantor_name
    grantee_name
    mortgages {
      lender_name
      mortgage_amount
    }
  }
}

query($area: geometry!) {
  parcel_boundary(where: { geom: { _st_contains: $area } }, limit: 500) {
    cherre_parcel_id
    tax_assessor {
      assessed_value_total
      land_use_code
    }
  }
}

query {
  tax_assessor_aggregate(where: { situs_zip_code: { _eq: "33139" } }) {
    aggregate {
      count
      sum { assessed_value_total }
      avg { assessed_value_total }
    }
  }
}

query {
  owner(where: { owner_name: { _ilike: "%acme holdings%" } }, limit: 10) {
    cherre_owner_id
    owner_name
    mailing_address
    properties {
      cherre_property_id
      tax_assessor { assessed_value_total }
    }
  }
}
